2929 void VPlanTransforms::addActiveLaneMask(
2930     VPlan &Plan, bool UseActiveLaneMaskForControlFlow,
2931     bool DataAndControlFlowWithoutRuntimeCheck) {
2932   assert((!DataAndControlFlowWithoutRuntimeCheck ||
2933           UseActiveLaneMaskForControlFlow) &&
2934          "DataAndControlFlowWithoutRuntimeCheck implies "
2935          "UseActiveLaneMaskForControlFlow");
2936 
2937   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
2938   auto *FoundWidenCanonicalIVUser = find_if(
2939       LoopRegion->getCanonicalIV()->users(), IsaPred<VPWidenCanonicalIVRecipe>);
2940   assert(FoundWidenCanonicalIVUser &&
2941          "Must have widened canonical IV when tail folding!");
2942   VPSingleDefRecipe *HeaderMask = vputils::findHeaderMask(Plan);
2943   auto *WideCanonicalIV =
2944       cast<VPWidenCanonicalIVRecipe>(*FoundWidenCanonicalIVUser);
2945   VPSingleDefRecipe *LaneMask;
2946   if (UseActiveLaneMaskForControlFlow) {
2947     LaneMask = addVPLaneMaskPhiAndUpdateExitBranch(Plan, false);
2948   } else {
2949     VPBuilder B = VPBuilder::getToInsertAfter(WideCanonicalIV);
2950     VPValue *ALMMultiplier =
2951         Plan.getConstantInt(LoopRegion->getCanonicalIVType(), 1);
2952     LaneMask =
2953         B.createNaryOp(VPInstruction::ActiveLaneMask,
2954                        {WideCanonicalIV, Plan.getTripCount(), ALMMultiplier},
2955                        nullptr, "active.lane.mask");
2956   }
2957 
2958   // Walk users of WideCanonicalIV and replace the header mask of the form
2959   // (ICMP_ULE, WideCanonicalIV, backedge-taken-count) with an active-lane-mask,
2960   // removing the old one to ensure there is always only a single header mask.
2961   HeaderMask->replaceAllUsesWith(LaneMask);
2962   HeaderMask->eraseFromParent();
2963 }
