2965 template <typename Op0_t, typename Op1_t> struct RemoveMask_match {
2966   Op0_t In;
2967   Op1_t &Out;
2968 
2969   RemoveMask_match(const Op0_t &In, Op1_t &Out) : In(In), Out(Out) {}
2970 
2971   template <typename OpTy> bool match(OpTy *V) const {
2972     if (m_Specific(In).match(V)) {
2973       Out = nullptr;
2974       return true;
2975     }
2976     return m_LogicalAnd(m_Specific(In), m_VPValue(Out)).match(V);
2977   }
2978 };
