2980 /// Match a specific mask \p In, or a combination of it (logical-and In, Out).
2981 /// Returns the remaining part \p Out if so, or nullptr otherwise.
2982 template <typename Op0_t, typename Op1_t>
2983 static inline RemoveMask_match<Op0_t, Op1_t> m_RemoveMask(const Op0_t &In,
2984                                                           Op1_t &Out) {
2985   return RemoveMask_match<Op0_t, Op1_t>(In, Out);
