3088 /// Optimize away any EVL-based header masks to VP intrinsic based recipes.
3089 /// The transforms here need to preserve the original semantics.
3090 void VPlanTransforms::optimizeEVLMasks(VPlan &Plan) {
3091   // Find the EVL-based header mask if it exists: icmp ult step-vector, EVL
3092   VPValue *HeaderMask = nullptr, *EVL = nullptr;
3093   for (VPRecipeBase &R : *Plan.getVectorLoopRegion()->getEntryBasicBlock()) {
3094     if (match(&R, m_SpecificICmp(CmpInst::ICMP_ULT, m_StepVector(),
3095                                  m_VPValue(EVL))) &&
3096         match(EVL, m_EVL(m_VPValue()))) {
3097       HeaderMask = R.getVPSingleValue();
3098       break;
